def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 1.5:
            priorities[i] = ratio ** 3
        elif 1 <= ratio <= 1.5:
            priorities[i] = ratio ** 2 + np.log(capacity + 1)
        else:
            sum_terms = 0
            for j in range(1, int(capacity)+1):
                sum_terms += np.sin(ratio * j) / (j + 1)
            priorities[i] = -np.log(capacity) + sum_terms
        if capacity % 2 == 0:
            priorities[i] *= 0.9
        else:
            priorities[i] *= 1.1
    return priorities
